#nullable enable // autogenerated

using System.Linq;
using MVZ2.GameContent.Buffs.Projectiles;
using MVZ2.Vanilla.Callbacks;
using PVZEngine.Callbacks;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Buffs;
using MVZ2.GameContent.Contraptions;

namespace MVZ2.GameContent.Projectiles
{
    [AutoEntityBehaviourDefinition(VanillaProjectileNames.PurpleKnife)]
    public class PurpleKnife : EntityBehaviourDefinition, IElectrifyBehaviour
    {
        public PurpleKnife(string nsp, string name) : base(nsp, name)
        {
            AddTrigger(VanillaLevelCallbacks.POST_PROJECTILE_HIT, PostHitEntityCallback);
        }
        public void Electrify(Entity entity, Entity teslaCoil)
        {
            var electrifiedBuff = entity.GetFirstBuff<ElectrifiedBuff>();
            if (electrifiedBuff == null)
            {
                entity.AddBuff<ElectrifiedBuff>();
            }
        }
        private void PostHitEntityCallback(VanillaLevelCallbacks.PostProjectileHitParams param, CallbackResult result)
        {
            var hitResult = param.hit;
            var projectile = hitResult.Projectile;
            if (!projectile.Definition.HasBehaviour(this))
                return;
            hitResult.Pierce = true;
        }
    }
}
